import base64
import zipfile
import io
import zlib
import gzip

def hexdump(b, n=32):
    return b[:n].hex()

def try_decompress(payload: bytes, out_prefix="out"):
    print("len:", len(payload))
    print("head 4 bytes:", hexdump(payload, 4))

    # 1) Try ZIP container detection
    if payload[:2] == b'PK':
        print("Detected PK zip header -> try python zipfile")
        try:
            with zipfile.ZipFile(io.BytesIO(payload)) as z:
                print("ZIP files:", z.namelist())
                # read first file (auto-decompress)
                for name in z.namelist():
                    data = z.read(name)
                    print(f"-> file {name} len={len(data)} (auto-decompressed)")
                return True
        except Exception as ex:
            print("zipfile error:", ex)

    # 2) Try gzip
    try:
        dec = zlib.decompress(payload, wbits=31)  # 16 + 15 to auto-detect gzip
        print("zlib with wbits=31 succeeded, len:", len(dec))
        return True
    except Exception as ex:
        print("wbits=31 failed:", ex)

    # 3) Try zlib wrapper (wbits=15)
    try:
        dec = zlib.decompress(payload, wbits=15)
        print("zlib with wbits=15 succeeded, len:", len(dec))
        return True
    except Exception as ex:
        print("wbits=15 failed:", ex)

    # 4) Try raw deflate (wbits=-15)
    try:
        dec = zlib.decompress(payload, wbits=-15)
        print("raw deflate (wbits=-15) succeeded, len:", len(dec))
        return True
    except Exception as ex:
        print("wbits=-15 failed:", ex)

    # 5) As a last resort, try gzip module direct (might also error)
    try:
        with gzip.GzipFile(fileobj=io.BytesIO(payload)) as g:
            dec = g.read()
            print("gzip.GzipFile succeeded, len:", len(dec))
            return True
    except Exception as ex:
        print("gzip.GzipFile failed:", ex)

    print("All automatic attempts failed.")
    return False

# 用法示例：
# payload = ...   # bytes you want to test
# try_decompress(payload)


def decode():
    data = ""
    decoded = base64.b64decode(data)

    # with open("vmcodes.bin", "wb") as f:
    #     f.write(decoded)

    # print("finished wrote output.bin")

    return decoded


def map_function(t, r, key):
    """
    对应 JS 的 _(t, r)
    t: 单个字符 (string)
    r: 该字符的 index
    key: JS 中 this (即 e % 256)
    """
    # JS: (this + this % 10 * r) % 256
    key2 = (key + (key % 10) * r) % 256

    # JS: t.charCodeAt(0) ^ key2
    return (t ^ key2)


def uint8array_from_data(r, key):
    """
    等价于 JS 的：
    Uint8Array.from(r.slice(8), _, key)

    r: base64 解码后的字符串
    key: e % 256
    """
    r1 = r[:8]
    r2 = r[8:]  # JS: r.slice(8)

    out = []
    for i, ch in enumerate(r2):
        out.append(map_function(ch, i, key))

    # 返回 Python bytes（类似 Uint8Array）
    return bytes(out)

if __name__ == "__main__":
    
    decoded = decode()
    e = 0
    for n in range(4, 8):
        e += decoded[n]
    
    bytes = uint8array_from_data(decoded, e % 256)

    # 测试压缩类型
    # try_decompress(bytes)


    wbits = -15 
    # wbits = -15 的意思
    # 表示解压 “raw deflate” 格式（原始 Deflate 数据流）
    # 也就是说：
    # 没有 zlib 头（2 字节）
    # 没有 gzip 头（10+ 字节）
    # 没有校验字段
    # 仅仅是裸的 DEFLATE 压缩流
    # 它对应 JS 中的：
    # pako.inflateRaw()
    # 或者某些浏览器内部的 raw deflate 解码器
    # | wbits 值 | 格式        | 描述                            |
    # | ------- | ----------- | ----------------------------- |
    # | **+15** | zlib        | 有 zlib header 与 checksum      |
    # | **+31** | gzip        | gzip 格式文件                     |
    # | **-15** | raw deflate | **没有任何 header** 的 DEFLATE 数据流 |
    bytes = raw = zlib.decompress(bytes, wbits)
    with open("vmcodes.bin", "wb") as f:
        f.write(bytes)

    print("finished wrote vmcodes.bin")



